import { useState } from "react";

const API = "http://127.0.0.1:8000";

export default function BankingChat() {
  const [messages, setMessages] = useState([{role:"bot",text:"Welcome to AIB Bank. I am your virtual assistant. How can I help you today?",blocked:false}]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [securityLog, setSecurityLog] = useState([]);
  const [currentStatus, setCurrentStatus] = useState("idle");
  const [lastConfidence, setLastConfidence] = useState(null);

  async function sendMessage() {
    if (!input.trim()) return;
    setMessages(p=>[...p,{role:"user",text:input,blocked:false}]);
    setInput(""); setLoading(true); setCurrentStatus("checking");
    try {
      const r = await fetch(`${API}/api/v1/chat`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({prompt:input})});
      const d = await r.json();
      if(d.blocked){
        setCurrentStatus("blocked"); setLastConfidence(d.confidence);
        setSecurityLog(p=>[{time:new Date().toLocaleTimeString(),status:"BLOCKED",confidence:Math.round(d.confidence*100),prompt:input.slice(0,45)},...p.slice(0,9)]);
        setMessages(p=>[...p,{role:"bot",text:"Your message has been blocked. A prompt injection attack was detected.",blocked:true,confidence:d.confidence}]);
      } else {
        setCurrentStatus("safe");
        setSecurityLog(p=>[{time:new Date().toLocaleTimeString(),status:"SAFE",confidence:0,prompt:input.slice(0,45)},...p.slice(0,9)]);
        setMessages(p=>[...p,{role:"bot",text:d.ai_response,blocked:false}]);
      }
    } catch(e){ setCurrentStatus("idle"); setMessages(p=>[...p,{role:"bot",text:"Sorry, cannot connect to server.",blocked:false}]); }
    setLoading(false);
  }

  const totalBlocked = securityLog.filter(l=>l.status==="BLOCKED").length;
  const totalSafe = securityLog.filter(l=>l.status==="SAFE").length;
  const suggestions = ["What are your opening hours?","How do I apply for a mortgage?","What are current interest rates?","How do I report a lost card?"];

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100vh",fontFamily:"Georgia,'Times New Roman',serif",background:"#F0F4F8"}}>

      <div style={{background:"#0F1F4B",padding:"0 28px",height:68,display:"flex",alignItems:"center",justifyContent:"space-between",boxShadow:"0 2px 12px rgba(0,0,0,0.25)"}}>
        <div style={{display:"flex",alignItems:"center",gap:16}}>
          <div style={{background:"#FFFFFF",borderRadius:8,width:48,height:48,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:"bold",fontSize:18,color:"#0F1F4B",letterSpacing:1}}>AIB</div>
          <div>
            <div style={{color:"#FFFFFF",fontSize:18,fontWeight:"bold"}}>Allied Irish Banks</div>
            <div style={{color:"#93C5FD",fontSize:12,marginTop:2}}>Virtual Customer Assistant</div>
          </div>
        </div>
        <div style={{display:"flex",gap:10}}>
          <div style={{background:"#007B5F",borderRadius:20,padding:"6px 16px",color:"#FFFFFF",fontSize:11,fontWeight:"bold"}}>3 Layer Security Active</div>
          <div style={{background:"rgba(255,255,255,0.1)",borderRadius:20,padding:"6px 16px",color:"#FFFFFF",fontSize:11}}>Powered by ChatGPT</div>
        </div>
      </div>

      <div style={{display:"flex",flex:1,overflow:"hidden"}}>

        <div style={{flex:1,display:"flex",flexDirection:"column",background:"#F0F4F8"}}>
          <div style={{background:"#FFFFFF",padding:"12px 24px",borderBottom:"1px solid #E0E6EF",display:"flex",alignItems:"center",gap:12}}>
            <div style={{width:10,height:10,borderRadius:"50%",background:"#007B5F"}}></div>
            <div style={{fontSize:14,fontWeight:"bold",color:"#0F1F4B"}}>AIB Customer Support</div>
            <div style={{fontSize:12,color:"#6B7280",marginLeft:"auto"}}>Protected by Prompt Injection Detection Framework</div>
          </div>

          <div style={{flex:1,overflowY:"auto",padding:"24px 20px",display:"flex",flexDirection:"column",gap:14}}>
            {messages.map((msg,i)=>(
              <div key={i}>
                {msg.role==="user" && (
                  <div style={{display:"flex",justifyContent:"flex-end"}}>
                    <div style={{background:"#0F1F4B",color:"#FFFFFF",padding:"12px 18px",borderRadius:"20px 20px 4px 20px",maxWidth:"65%",fontSize:14,lineHeight:1.6,boxShadow:"0 2px 8px rgba(15,31,75,0.2)"}}>{msg.text}</div>
                  </div>
                )}
                {msg.role==="bot" && !msg.blocked && (
                  <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                    <div style={{width:36,height:36,background:"#0F1F4B",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",color:"#FFFFFF",fontSize:11,fontWeight:"bold",flexShrink:0}}>AIB</div>
                    <div style={{background:"#FFFFFF",color:"#1F2937",padding:"12px 18px",borderRadius:"20px 20px 20px 4px",maxWidth:"65%",fontSize:14,lineHeight:1.6,boxShadow:"0 1px 4px rgba(0,0,0,0.08)",border:"1px solid #E0E6EF"}}>{msg.text}</div>
                  </div>
                )}
                {msg.role==="bot" && msg.blocked && (
                  <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                    <div style={{width:36,height:36,background:"#CC0000",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",color:"#FFFFFF",fontSize:16,fontWeight:"bold",flexShrink:0}}>!</div>
                    <div style={{background:"#FFF0F0",color:"#7F1D1D",padding:"14px 18px",borderRadius:"20px 20px 20px 4px",maxWidth:"68%",fontSize:14,lineHeight:1.6,border:"1.5px solid #CC0000"}}>
                      <div style={{fontWeight:"bold",fontSize:13,marginBottom:6,color:"#CC0000"}}>Security Alert — Message Blocked</div>
                      <div>{msg.text}</div>
                      {msg.confidence && <div style={{marginTop:8,fontSize:11,color:"#CC0000",fontWeight:"bold"}}>Detection Confidence: {Math.round(msg.confidence*100)}%</div>}
                    </div>
                  </div>
                )}
              </div>
            ))}
            {loading && (
              <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                <div style={{width:36,height:36,background:"#0F1F4B",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",color:"#FFFFFF",fontSize:11,fontWeight:"bold",flexShrink:0}}>AIB</div>
                <div style={{background:"#FFFFFF",color:"#6B7280",padding:"12px 18px",borderRadius:"20px 20px 20px 4px",fontSize:14,border:"1px solid #E0E6EF"}}>AIB Assistant is typing...</div>
              </div>
            )}
          </div>

          <div style={{padding:"10px 20px",background:"#FFFFFF",borderTop:"1px solid #E0E6EF",display:"flex",gap:8,flexWrap:"wrap"}}>
            {suggestions.map((s,i)=>(
              <button key={i} onClick={()=>setInput(s)} style={{background:"#EEF4FF",color:"#0F1F4B",border:"1px solid #C7D9F5",borderRadius:20,padding:"6px 14px",fontSize:12,cursor:"pointer",fontFamily:"Georgia,serif"}}>{s}</button>
            ))}
          </div>

          <div style={{background:"#FFFFFF",borderTop:"1px solid #E0E6EF",padding:"16px 20px",display:"flex",gap:12,alignItems:"center"}}>
            <input value={input} onChange={e=>setInput(e.target.value)} onKeyPress={e=>e.key==="Enter"&&sendMessage()} placeholder="Type your message to AIB Bank..." style={{flex:1,padding:"12px 18px",border:"1.5px solid #C7D9F5",borderRadius:25,fontSize:14,fontFamily:"Georgia,serif",outline:"none",color:"#1F2937",background:"#F8FAFF"}}/>
            <button onClick={sendMessage} disabled={loading||!input.trim()} style={{background:"#0F1F4B",color:"#FFFFFF",border:"none",borderRadius:25,padding:"12px 28px",fontSize:14,fontWeight:"bold",cursor:"pointer",fontFamily:"Georgia,serif",boxShadow:"0 2px 8px rgba(15,31,75,0.3)"}}>
              {loading?"Sending...":"Send"}
            </button>
          </div>
        </div>

        <div style={{width:290,display:"flex",flexDirection:"column",background:"#FFFFFF",borderLeft:"1px solid #E0E6EF"}}>
          <div style={{background:"#0F1F4B",padding:"14px 18px"}}>
            <div style={{fontSize:14,fontWeight:"bold",color:"#FFFFFF"}}>Security Monitor</div>
            <div style={{fontSize:11,color:"#93C5FD",marginTop:2}}>Prompt Injection Detection Framework</div>
          </div>

          <div style={{display:"flex",borderBottom:"1px solid #E0E6EF"}}>
            {[{label:"Checked",val:securityLog.length,color:"#0F1F4B"},{label:"Blocked",val:totalBlocked,color:"#CC0000"},{label:"Safe",val:totalSafe,color:"#007B5F"}].map((stat,i)=>(
              <div key={i} style={{flex:1,padding:"14px 8px",textAlign:"center",borderRight:i<2?"1px solid #E0E6EF":"none"}}>
                <div style={{fontSize:24,fontWeight:"bold",color:stat.color,fontFamily:"Georgia,serif"}}>{stat.val}</div>
                <div style={{fontSize:10,color:"#6B7280",marginTop:3}}>{stat.label}</div>
              </div>
            ))}
          </div>

          <div style={{margin:14,padding:14,borderRadius:10,background:currentStatus==="blocked"?"#FFF0F0":currentStatus==="safe"?"#F0FFF8":currentStatus==="checking"?"#FFFBEB":"#F8FAFF",border:`1.5px solid ${currentStatus==="blocked"?"#CC0000":currentStatus==="safe"?"#007B5F":currentStatus==="checking"?"#D97706":"#C7D9F5"}`}}>
            <div style={{fontSize:12,fontWeight:"bold",color:currentStatus==="blocked"?"#CC0000":currentStatus==="safe"?"#007B5F":currentStatus==="checking"?"#B45309":"#0F1F4B",marginBottom:6,fontFamily:"Georgia,serif"}}>
              {currentStatus==="idle"&&"Awaiting Message"}
              {currentStatus==="checking"&&"Analysing Message..."}
              {currentStatus==="safe"&&"Message Safe"}
              {currentStatus==="blocked"&&"Attack Detected"}
            </div>
            <div style={{fontSize:11,color:"#6B7280",lineHeight:1.5}}>
              {currentStatus==="idle"&&"All messages checked through 3 security layers before reaching AIB assistant."}
              {currentStatus==="checking"&&"Running through Layer 1, Layer 2 and Layer 3..."}
              {currentStatus==="safe"&&"All 3 layers confirmed safe. Message passed to ChatGPT."}
              {currentStatus==="blocked"&&`Attack detected with ${lastConfidence?Math.round(lastConfidence*100):0}% confidence. Blocked before reaching AI.`}
            </div>
          </div>

          <div style={{margin:"0 14px 14px",padding:14,background:"#F8FAFF",borderRadius:10,border:"1px solid #E0E6EF"}}>
            <div style={{fontSize:12,fontWeight:"bold",color:"#0F1F4B",marginBottom:12,fontFamily:"Georgia,serif"}}>Detection Layers</div>
            {[{name:"Layer 1 — Rule-Based",desc:"25 attack signatures"},{name:"Layer 2 — BERT AI",desc:"Semantic understanding"},{name:"Layer 3 — LLM Guardrail",desc:"Output verification"}].map((l,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
                <div style={{width:8,height:8,borderRadius:"50%",background:"#007B5F",flexShrink:0}}></div>
                <div style={{flex:1}}>
                  <div style={{fontSize:11,fontWeight:"bold",color:"#0F1F4B",fontFamily:"Georgia,serif"}}>{l.name}</div>
                  <div style={{fontSize:10,color:"#6B7280"}}>{l.desc}</div>
                </div>
                <div style={{fontSize:10,fontWeight:"bold",color:"#007B5F"}}>Active</div>
              </div>
            ))}
          </div>

          <div style={{margin:"0 14px",flex:1,overflow:"hidden",display:"flex",flexDirection:"column"}}>
            <div style={{fontSize:12,fontWeight:"bold",color:"#0F1F4B",marginBottom:10,fontFamily:"Georgia,serif"}}>Detection Log</div>
            {securityLog.length===0&&<div style={{fontSize:11,color:"#9CA3AF",fontStyle:"italic"}}>No activity yet.</div>}
            <div style={{overflowY:"auto",flex:1}}>
              {securityLog.map((log,i)=>(
                <div key={i} style={{padding:"8px 10px",borderRadius:8,marginBottom:6,background:log.status==="BLOCKED"?"#FFF0F0":"#F0FFF8",border:`1px solid ${log.status==="BLOCKED"?"#FCA5A5":"#86EFAC"}`}}>
                  <div style={{display:"flex",justifyContent:"space-between"}}>
                    <span style={{fontWeight:"bold",fontSize:11,color:log.status==="BLOCKED"?"#CC0000":"#007B5F",fontFamily:"Georgia,serif"}}>{log.status}</span>
                    <span style={{fontSize:10,color:"#9CA3AF"}}>{log.time}</span>
                  </div>
                  {log.status==="BLOCKED"&&<div style={{fontSize:10,color:"#CC0000",marginTop:2}}>Confidence: {log.confidence}%</div>}
                  <div style={{fontSize:10,color:"#6B7280",marginTop:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{log.prompt}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
